CREATE OR REPLACE FUNCTION OFSERM.Incurred_CVA_Rate_Parameters(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    MERGE  INTO FSI_INCURRED_CVA_LOSS_CALC TT USING (   SELECT * FROM (  SELECT  /*+ PARALLEL(4) */ FSI_INCURRED_CVA_LOSS_CALC.N_RUN_SKEY,FSI_INCURRED_CVA_LOSS_CALC.N_MIS_DATE_SKEY,FSI_INCURRED_CVA_LOSS_CALC.N_ACCT_SKEY,FSI_INCURRED_CVA_LOSS_CALC.N_CAP_APPROACH_TYPE_SKEY,(FSI_INCURRED_CVA_LOSS_CALC.N_CREDIT_SPREAD_T) AS  T_1500450926438_0,   (CASE  WHEN  ( ((1=1)) ) THEN 10 ELSE 11 END)  AS COND_1500450926438_10 ,  (fn_com_market_credit_spread(CASE WHEN 1 = 1 THEN DIM_DATES.d_calendar_date ELSE NULL END , CASE WHEN 1 = 1 THEN DIM_RUN.n_run_skey ELSE NULL END , CASE WHEN 1=1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_RESIDUAL_MATURITY ELSE NULL END , 'Y', CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_BASEL_PARTY_RATING ELSE NULL END , CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.n_counterparty_skey ELSE NULL END , CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.n_spread_std_party_type_skey ELSE NULL END , 'N')) AS EXP_1500450926438_10,(FSI_INCURRED_CVA_LOSS_CALC.N_CREDIT_SPREAD_T) AS EXP_1500450926438_11 ,(FSI_INCURRED_CVA_LOSS_CALC.N_RISK_PREMIUM_T) AS  T_1500450926438_1,   (CASE  WHEN  ( ((1=1)) ) THEN 20 ELSE 21 END)  AS COND_1500450926438_20 ,  (fn_com_cpty_risk_premium(CASE WHEN 1 = 1 THEN DIM_DATES.d_calendar_date ELSE NULL END , CASE WHEN 1 = 1 THEN DIM_RUN.n_run_skey ELSE NULL END , CASE WHEN 1=1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_RESIDUAL_MATURITY ELSE NULL END , 'Y', CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.n_counterparty_skey ELSE NULL END )) AS EXP_1500450926438_20,(FSI_INCURRED_CVA_LOSS_CALC.N_RISK_PREMIUM_T) AS EXP_1500450926438_21 ,(FSI_INCURRED_CVA_LOSS_CALC.N_CREDIT_SPREAD_0) AS  T_1500450926438_2,   (CASE  WHEN  ( ((1=1)) ) THEN 30 ELSE 31 END)  AS COND_1500450926438_30 ,  (fn_com_market_credit_spread(CASE WHEN 1 = 1 THEN DIM_DATES.d_calendar_date ELSE NULL END , CASE WHEN 1 = 1 THEN DIM_RUN.n_run_skey ELSE NULL END , CASE WHEN 1=1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_ORIGINAL_MATURITY ELSE NULL END , 'Y', CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_BASEL_PARTY_RATING ELSE NULL END , CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.n_counterparty_skey ELSE NULL END , CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.n_spread_std_party_type_skey ELSE NULL END , 'Y')) AS EXP_1500450926438_30,(FSI_INCURRED_CVA_LOSS_CALC.N_CREDIT_SPREAD_0) AS EXP_1500450926438_31 ,(FSI_INCURRED_CVA_LOSS_CALC.N_RISK_PREMIUM_0) AS  T_1500450926438_3,   (CASE  WHEN  ( ((1=1)) ) THEN 40 ELSE 41 END)  AS COND_1500450926438_40 ,  (fn_com_cpty_risk_premium(CASE WHEN 1 = 1 THEN DIM_DATES.d_calendar_date ELSE NULL END , CASE WHEN 1 = 1 THEN DIM_RUN.n_run_skey ELSE NULL END , CASE WHEN 1=1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_ORIGINAL_MATURITY ELSE NULL END , 'Y', CASE WHEN 1 = 1 THEN FSI_INCURRED_CVA_LOSS_CALC.n_counterparty_skey ELSE NULL END )) AS EXP_1500450926438_40,(FSI_INCURRED_CVA_LOSS_CALC.N_RISK_PREMIUM_0) AS EXP_1500450926438_41 ,(FSI_INCURRED_CVA_LOSS_CALC.N_DISCOUNT_RATE) AS  T_1500450926438_4,   (CASE  WHEN  ( ((1=1)) ) THEN 50 ELSE 51 END)  AS COND_1500450926438_50 ,  (FN_COM_IRC_YIELD_CURVE(CASE WHEN 1 = 1 THEN DIM_RUN.n_run_skey ELSE NULL END , CASE WHEN 1 = 1 THEN DIM_DATES.d_calendar_date ELSE NULL END , 365*(CASE WHEN 1=1 THEN FSI_INCURRED_CVA_LOSS_CALC.N_RESIDUAL_MATURITY ELSE NULL END  - 1), CASE WHEN 1 = 1 THEN RUN_EXE_PARAMETERS_RCY.v_param_value_code ELSE NULL END ,'Z')) AS EXP_1500450926438_50,(FSI_INCURRED_CVA_LOSS_CALC.N_DISCOUNT_RATE) AS EXP_1500450926438_51  FROM  FSI_INCURRED_CVA_LOSS_CALC LEFT OUTER JOIN DIM_RUN ON FSI_INCURRED_CVA_LOSS_CALC.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY LEFT OUTER JOIN DIM_DATES ON FSI_INCURRED_CVA_LOSS_CALC.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT OUTER JOIN RUN_PARAMETERS ON FSI_INCURRED_CVA_LOSS_CALC.N_RUN_PARAMETER_SETUP_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY AND RUN_PARAMETERS.N_RUN_SKEY = FSI_INCURRED_CVA_LOSS_CALC.N_RUN_SKEY AND RUN_PARAMETERS.N_DATE_SKEY = FSI_INCURRED_CVA_LOSS_CALC.N_MIS_DATE_SKEY LEFT OUTER JOIN DIM_RUN_IDENTIFIER ON DIM_RUN_IDENTIFIER.N_RUN_IDENTIFIER_SKEY = FSI_INCURRED_CVA_LOSS_CALC.N_RUN_IDENTIFIER_SKEY LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_INCURRED_CVA_LOSS_CALC.N_CAP_APPROACH_TYPE_SKEY INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_INCURRED_CVA_LOSS_CALC.N_CAP_RECORD_TYPE_SKEY  WHERE (1=1)  AND (DIM_RUN.N_RUN_SKEY = '870' AND DIM_DATES.D_CALENDAR_DATE = TO_DATE('20260331','yyyymmdd'))  ) WHERE (   (COND_1500450926438_10 <> 11)   OR  (COND_1500450926438_20 <> 21)  OR  (COND_1500450926438_30 <> 31)  OR  (COND_1500450926438_40 <> 41)  OR  (COND_1500450926438_50 <> 51) ) ) SS ON ( TT.N_RUN_SKEY= SS.N_RUN_SKEY AND TT.N_MIS_DATE_SKEY= SS.N_MIS_DATE_SKEY AND TT.N_ACCT_SKEY= SS.N_ACCT_SKEY AND TT.N_CAP_APPROACH_TYPE_SKEY= SS.N_CAP_APPROACH_TYPE_SKEY) WHEN MATCHED THEN UPDATE SET  TT.N_CREDIT_SPREAD_T=  CASE  WHEN  COND_1500450926438_10=10 THEN EXP_1500450926438_10 ELSE EXP_1500450926438_11 END  , TT.N_RISK_PREMIUM_T=  CASE  WHEN  COND_1500450926438_20=20 THEN EXP_1500450926438_20 ELSE EXP_1500450926438_21 END  , TT.N_CREDIT_SPREAD_0=  CASE  WHEN  COND_1500450926438_30=30 THEN EXP_1500450926438_30 ELSE EXP_1500450926438_31 END  , TT.N_RISK_PREMIUM_0=  CASE  WHEN  COND_1500450926438_40=40 THEN EXP_1500450926438_40 ELSE EXP_1500450926438_41 END  , TT.N_DISCOUNT_RATE=  CASE  WHEN  COND_1500450926438_50=50 THEN EXP_1500450926438_50 ELSE EXP_1500450926438_51 END;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
